import React from 'react';

function buildRange(page, total, siblings) {
  const range = [];
  for (let p = 1; p <= total; p++) {
    if (p === 1 || p === total || Math.abs(p - page) <= siblings) {
      range.push(p);
    } else if (range[range.length - 1] !== '…') {
      range.push('…');
    }
  }
  return range;
}

export default function Pagination({ page, total, onChange, siblings = 1 }) {
  if (total <= 1) return null;
  const range = buildRange(page, total, siblings);

  const base = {
    minWidth: 36,
    height: 36,
    border: '1px solid #ddd',
    background: '#fff',
    cursor: 'pointer',
    borderRadius: 6,
  };

  return (
    <nav aria-label="Pagination" style={{ display: 'flex', gap: 6, alignItems: 'center' }}>
      <button style={base} disabled={page === 1} onClick={() => onChange(page - 1)}>‹</button>
      {range.map((p, i) =>
        p === '…' ? (
          <span key={`e${i}`} style={{ minWidth: 24, textAlign: 'center', color: '#999' }}>…</span>
        ) : (
          <button
            key={p}
            aria-current={p === page ? 'page' : undefined}
            onClick={() => onChange(p)}
            style={{
              ...base,
              background: p === page ? '#2563eb' : '#fff',
              color: p === page ? '#fff' : '#333',
              fontWeight: p === page ? 700 : 400,
            }}
          >
            {p}
          </button>
        )
      )}
      <button style={base} disabled={page === total} onClick={() => onChange(page + 1)}>›</button>
    </nav>
  );
}

