import { Component, Input, Output, EventEmitter } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

@Component({
  selector: 'app-pagination',
  template: `
    <nav *ngIf="total > 1" aria-label="Pagination" style="display: flex; gap: 6px; align-items: center;">
      <button [disabled]="page === 1" (click)="go(page - 1)"
        style="min-width: 36px; height: 36px; border: 1px solid #ddd; background: #fff; cursor: pointer; border-radius: 6px;">‹</button>
      <ng-container *ngFor="let p of range; let i = index">
        <span *ngIf="p === '…'; else num" style="min-width: 24px; text-align: center; color: #999;">…</span>
        <ng-template #num>
          <button
            (click)="go(asNumber(p))"
            [attr.aria-current]="p === page ? 'page' : null"
            [style.background]="p === page ? '#2563eb' : '#fff'"
            [style.color]="p === page ? '#fff' : '#333'"
            [style.font-weight]="p === page ? 700 : 400"
            style="min-width: 36px; height: 36px; border: 1px solid #ddd; cursor: pointer; border-radius: 6px;"
          >{{ p }}</button>
        </ng-template>
      </ng-container>
      <button [disabled]="page === total" (click)="go(page + 1)"
        style="min-width: 36px; height: 36px; border: 1px solid #ddd; background: #fff; cursor: pointer; border-radius: 6px;">›</button>
    </nav>
  `,
})
export class PaginationComponent {
  @Input() page = 1;
  @Input() total = 1;
  @Input() siblings = 1;
  @Output() pageChange = new EventEmitter<number>();

  go(p: number): void {
    this.pageChange.emit(p);
  }

  asNumber(p: number | string): number {
    return p as number;
  }

  get range(): (number | string)[] {
    const r: (number | string)[] = [];
    for (let p = 1; p <= this.total; p++) {
      if (p === 1 || p === this.total || Math.abs(p - this.page) <= this.siblings) {
        r.push(p);
      } else if (r[r.length - 1] !== '…') {
        r.push('…');
      }
    }
    return r;
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Pagination Demo</h1>
      <p>Showing page <strong>{{ page }}</strong> of {{ total }}</p>
      <app-pagination [page]="page" [total]="total" [siblings]="1" (pageChange)="page = $event"></app-pagination>
    </div>
  `,
})
export class AppComponent {
  page = 1;
  total = 12;
}

@NgModule({
  declarations: [AppComponent, PaginationComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
